using System;

class Product {
    public required string Name { get; init; }
    public required decimal Price { get; init; }
    public string Category { get; init; } = "General";
}

class Program {
    static void Main() {
        var p = new Product { Name = "Widget", Price = 9.99m };
        Console.WriteLine($"{p.Name}: {p.Price:C} [{p.Category}]");
    }
}

using System;

class Rectangle {
    public double Width { get; set; }
    public double Height { get; set; }
    public double Area => Width * Height;
    public double Perimeter => 2 * (Width + Height);
    public bool IsSquare => Width == Height;
}

class Program {
    static void Main() {
        var r = new Rectangle { Width = 4, Height = 4 };
        Console.WriteLine($"area={r.Area} perimeter={r.Perimeter} square={r.IsSquare}");
    }
}

using System;

class Counter {
    public int Count { get; private set; } = 0;
    public void Increment() => Count++;
    public void Reset() => Count = 0;
}

class Program {
    static void Main() {
        var c = new Counter();
        c.Increment(); c.Increment(); c.Increment();
        Console.WriteLine(c.Count);
        c.Reset();
        Console.WriteLine(c.Count);
        // c.Count = 5; // won't compile
    }
}

using System;

class AppConfig {
    public static string Version { get; } = "1.0.0";
    public static string AppName { get; set; } = "MyApp";
}

class Program {
    static void Main() {
        Console.WriteLine($"{AppConfig.AppName} v{AppConfig.Version}");
        AppConfig.AppName = "BetterApp";
        Console.WriteLine(AppConfig.AppName);
    }
}
